-- Seed Settings (insert only if not exists to prevent overwriting user keys)
INSERT INTO settings (key_name, val_value) 
SELECT 'ELEVENLABS_API_KEY', '' FROM dual WHERE NOT EXISTS (SELECT 1 FROM settings WHERE key_name = 'ELEVENLABS_API_KEY');

INSERT INTO settings (key_name, val_value) 
SELECT 'ELEVENLABS_VOICE_ID', '' FROM dual WHERE NOT EXISTS (SELECT 1 FROM settings WHERE key_name = 'ELEVENLABS_VOICE_ID');

INSERT INTO settings (key_name, val_value) 
SELECT 'OPENROUTER_MODEL', 'anthropic/claude-opus-4.8' FROM dual WHERE NOT EXISTS (SELECT 1 FROM settings WHERE key_name = 'OPENROUTER_MODEL');


-- Seed Prompt History (upsert by ID)
MERGE INTO prompt_history (id, title, prompt) KEY(id) VALUES 
(1, 'Antigravity für Designer', 'Erstelle eine Präsentation über Antigravity für Designer. Sie soll locker und bildhaft sein. Kläre den Unterschied zwischen Chatbots und KI-Agenten. Zeige auf, dass Antigravity mehr als Text kann (z.B. Systemdiagnose, Ruckler beheben). Verwende das Bewerbungsprojekt als Praxisbeispiel (4 Teile: Unterlagen + Weblink, Masterprompt, Ergebnisse, Skripte/Tools).'),
(2, 'KI-Einsatz in Agenturen', 'Präsentation für Art Directors: Wie KI generative Bildgestaltung, UI Prototyping und repetitive Datei-Operationen automatisieren kann. Zeige konkrete Tool-Anbindungen und hebe hervor, dass kreative Kuration beim Menschen verbleibt.'),
(3, 'PC-Performance & Hardware für Designer', 'Erstelle einen Leitfaden für Kreative: Warum Photoshop, Illustrator und After Effects ruckeln. Diagnose-Schritte für CPU, RAM und VRAM, und wie man Caches automatisiert löschen kann.'),
(4, 'ElevenLabs API & Stimmenklon Guide', 'Erstelle eine Schritt-für-Schritt-Anleitung zur Nutzung von ElevenLabs. Zeige wie man einen Account anlegt, den API-Key ausliest, eine eigene Stimme per Instant Voice Cloning klont und die Voice-ID ausliest.');

