MERGE INTO projects (id, name, prompt, status, model_name, pptx_file_path, video_file_path, parent_id, version, version_group_id) KEY(id) VALUES 
(1, 'Antigravity - Einführung für Designer', 'Erstelle eine Präsentation über Antigravity für Designer. Sie soll locker und bildhaft sein. Kläre den Unterschied zwischen Chatbots und KI-Agenten. Zeige auf, dass Antigravity mehr als Text kann...', 'COMPLETED', 'anthropic/claude-opus-4.8', './data/projects/1/Antigravity_Vortrag.pptx', './data/projects/1/Antigravity_Vortrag_Video.mp4', NULL, 'v1', 1);

